sql:
SELECT COUNT(*)
FROM games
WHERE home_team = 'Phoenix' OR away_team = 'Phoenix';

SELECT line_id, ego, spread, over_under, money_line
FROM betting_lines
WHERE game_id = 0;

SELECT users.username, games.home_team, games.away_team
FROM users, games
WHERE users.user_id = 1 AND games.game_id = 1;

SELECT DISTINCT venue 
FROM games
WHERE game_type = 'regular season';

SELECT SUM(spread) AS Total_Spread
FROM betting_lines
WHERE game_id IS NOT NULL;

SELECT DISTINCT season 
FROM games
ORDER BY season ASC;

SELECT player_name 
FROM team_rosters 
WHERE player_name = 'Kirk Cousins';

SELECT team_rosters.player_name, teams.team_name 
FROM team_rosters 
INNER JOIN teams ON team_rosters.team_id = teams.team_id;

SELECT username, account_balance
FROM users
WHERE role = 'analyst' AND account_balance > (SELECT AVG(account_balance) FROM users);
